/// <summary>
/// extension class for form ITMFolioTable datasource ITMFolioTable
/// </summary>
[ExtensionOf(formDataSourceStr(ITMFolioTable, ITMFolioTable))]
final class ETGITMFolioTable_ITMFolioTable_DS_Extension
{

    }

Method.Source:
/// <summary>
/// update design for inbound orders of ITMFolioTable form
/// </summary>
/// <returns>int</returns>
public int active()
{
    int ret = next active();

    this.updateDesignITMFolioTable();

    return ret;
}

/// <summary>
/// update design for inbound orders of ITMFolioTable form
/// </summary>
public void updateDesignITMFolioTable()
{
    ITMTable            itmTableCurrent;
    boolean             enableOutboundDesign;
    FormDataSource      formDS          = this;
    ITMFolioTable       folioTable      = formDS.cursor();

    if (ITMParameters::find().ETGEnableLandedCostOutboundOrder == NoYes::No)
    {
        element.design().controlName(formControlStr(ITMFolioTable, ETGManageSalesOrderGroup)).visible(false);
    }

    else
    {
        select firstonly RecId, ETGLandedCostType from itmTableCurrent
        where itmTableCurrent.ShipId == folioTable.ShipId;

        if(itmTableCurrent.RecId && itmTableCurrent.ETGLandedCostType == ETGLandedCostType::Outbound)
        {
            element.design().controlName(formControlStr(ITMContainers, ManagePurchaseOrderGroup)).visible(false);
        }

        if(itmTableCurrent.RecId && itmTableCurrent.ETGLandedCostType == ETGLandedCostType::Inbound)
        {
            element.design().controlName(formControlStr(ITMContainers, ETGManageSalesOrderGroup)).visible(false);
        }
    }
}
